import{_ as r,o,c as e,a5 as a}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"学习记录 #0013：双向DC-DC与电池管理——UPS的能量枢纽","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0013：双向DC-DC与电池管理——UPS的能量枢纽","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第13课 — 双向DC-DC与电池管理（Phase 2核心拓扑） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0013-bidirectional-dcdc-battery.md","filePath":"content/power/archive/old-learning-records/0013-bidirectional-dcdc-battery.md","lastUpdated":null}'),i={name:"content/power/archive/old-learning-records/0013-bidirectional-dcdc-battery.md"};function n(l,t,s,c,d,g){return o(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="学习记录-0013-双向dc-dc与电池管理——ups的能量枢纽" tabindex="-1">学习记录 #0013：双向DC-DC与电池管理——UPS的能量枢纽 <a class="header-anchor" href="#学习记录-0013-双向dc-dc与电池管理——ups的能量枢纽" aria-label="Permalink to &quot;学习记录 #0013：双向DC-DC与电池管理——UPS的能量枢纽&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第13课 — 双向DC-DC与电池管理（Phase 2核心拓扑） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>双向DC-DC角色</strong>：充电Buck(高压→低压)，放电Boost(低压→高压)</li><li><strong>CC-CV充电</strong>：取min实现无缝切换，CC阶段CV环饱和，电压接近Vcv时自然接管</li><li><strong>放电控制</strong>：外环母线电压环+内环电池电流环，Boost模式</li><li><strong>模式切换</strong>：充电→放电&lt;1ms，母线电容维持电压</li><li><strong>SOC估算</strong>：安时积分法（5~10%精度）+ 开路电压法校准</li><li><strong>电池保护</strong>：过充/过放/过流/过温/低温/反接 6种保护</li><li><strong>均流控制</strong>：下垂法最简单（Vref=Vnom-Kdroop×Iout），无需通信线</li><li><strong>隔离方案</strong>：双向半桥LLC(1~10kW)或DAB双有源桥(5~100kW)</li><li><strong>电机对照</strong>：UPS充放电≈电机驱动/制动，但储能规模和切换频率不同</li></ol><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] 锂电池和铅酸电池的充电策略有什么区别？</li><li>[ ] DAB双有源桥的移相控制怎么实现？</li><li>[ ] 电池老化对SOC估算的影响怎么补偿？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第14课：多级联调——PFC+DC-DC+逆变器协同</p>',8)])])}const p=r(i,[["render",n]]);export{h as __pageData,p as default};
